reg [1:0]current_state;
reg [1:0] next_state;
parameter STATE_0=2'b00,STATE_1=2'b01, STATE_2=2'b10;


always @( current_state)//组合逻辑模块定义输出逻辑
	begin
		case(current_state)
			STATE_0: result <= 1'b0;
			STATE_1: result  <= 1'b1;
			default: result  <= 1'b0;
		endcase
	end

always @(posedge clk or negedge rst)//时序逻辑模块定义现态寄存器
	begin
		if(rst==1'b0)
			current_state <= STATE_0;
		else
			current_state  <= next_state;
	end

always @ (current_state or condition)//组合逻辑模块定义次态逻辑
	begin
		case(current_state)
			STATE_0:
				begin
					if(condition)
						next_state = STATE_1;
					else
						next_state =STATE_0;
				end
			STATE_1:
				begin
					if(condition)
						next_state =STATE_0;
					else
						next_state =STATE_1;
				end

			...

		endcase
	end

