module fd32(
	input wire [31:0] d_1,
	input wire [31:0] d_2,
	input wire ce,
	input wire clk,
	input wire clr,
	output reg [31:0] q_1 
);
function real r_fun;                   //不应使用实数型函数（function）
	input [31:0] d_1;
	input [31:0] d_2;
	real rx,ry,x2y2;	
begin
	rx = $bitstoreal (d_1);
	ry = $bitstoreal (d_2);
	x2y2 = (rx*rx)+(ry*ry);
	r_fun = x2y2;
end
endfunction
always@(posedge clk)
  begin
	if(clr)
		begin
		q_1 <= 32'h00000000;
		end	 
	else 
		if(ce)
			begin
			q_1 <= $realtobits(r_fun(d_1,d_2));
			end
		else 
			q_1 <= 32'hffffffff;
  end 	
endmodule

