案例代码:
module fd32(
	input wire d_1,
	input wire clk_1,
	input wire clk_2,
	input wire clr,
	output reg q_1 
);
reg in_1,in_2,in_3;

always@(posedge clk_1)
  begin
	if(clr)
		begin
		in_1 <= 1'b0;
		end	 
	else 
		in_1 <= d_1;
  end 

always@(posedge clk_2)
  begin
	if(clr)
		begin
		in_2 <= 1'b0;
		in_3 <= 1'b0;
		end	 
	else
		in_2 <= in_1;
		in_3 <= ~in_2;       //不应在同步器的两级触发器之间放置逻辑
		q_1 <= in_3;
  end 
endmodule

