module fd32(
	input wire d_1,
	input wire d_2,
	output reg [1:0] q_1,
	output reg [1:0] q_2 
);

initial 
fork        //在RTL描述中，不应使用fork-join语句

	q_1 = {d_1,d_2};
	q_2 = {d_2,d_1};

join 	
endmodule

